`<table st-persist="myTable" st-table="productsColl" st-safe-src="products" class="table table-striped">
`
and in my angular controller the directive of st-persist is the same as the example.

`
        .directive('stPersist', function () {
            return {
                require: '^stTable',
                link: function (scope, element, attr, ctrl) {
                    var nameSpace = attr.stPersist;

                    //save the table state every time it changes
                    scope.$watch(function () {
                        return ctrl.tableState();
                    }, function (newValue, oldValue) {
                        if (newValue !== oldValue) {
                            localStorage.setItem(nameSpace, JSON.stringify(newValue));
